const data = items[0].json;

// 🔹 Nome
const nomeUsuario = data.nome || "";

// 🔹 Contexto
const contexto = data.contexto || "";

// 🔹 Resultados
const resultados = data.resultados || [];

// 🔹 Código OTP (6 dígitos)
const codigo = data.codigo || "";

// 🔹 URL para completar cadastro
const completarCadastroUrl = data.completar_cadastro_url || "";

// 🔹 Número
const numero = data.telefone || data.numero;

// 🔹 Saudação
const saudacao = nomeUsuario ? `Oi, ${nomeUsuario}!` : "Oi!";

// 🔹 Ordenar por nota (maior primeiro) e pegar os 2 primeiros
const ordenados = [...resultados].sort(
  (a, b) => (b.item?.nota ?? 0) - (a.item?.nota ?? 0)
);
const top2 = ordenados.slice(0, 2);
const totalRestante = Math.max(0, resultados.length - top2.length);

// 🔹 Bloco de prévia dos fornecedores
let blocoFornecedores = "";
if (top2.length > 0) {
  blocoFornecedores = top2
    .map((r, i) => {
      const item = r.item || {};
      const nome = item.razao_social || "Fornecedor";
      const modelo = item.modelo_negocio ? ` (${item.modelo_negocio})` : "";
      const site = item.site ? `\n${item.site}` : "";
      return `${i + 1}. ${nome}${modelo}${site}`;
    })
    .join("\n\n");
}

// 🔹 Linha de contexto (se vier)
const linhaContexto = contexto
  ? `Separei alguns fornecedores pra "${contexto}".`
  : "Separei alguns fornecedores pra você.";

// 🔹 Mensagem
let mensagem = `${saudacao}
${linhaContexto}`;

if (blocoFornecedores) {
  mensagem += `

${blocoFornecedores}`;
}

if (totalRestante > 0) {
  mensagem += `

Tem mais ${totalRestante} no site, com contato e detalhes completos. Pra acessar é só confirmar seu número:`;
} else {
  mensagem += `

Pra ver os contatos e detalhes completos, é só confirmar seu número:`;
}

mensagem += `

Seu código é *${codigo}*

${completarCadastroUrl}

(o código vale por 15 minutos)

Qualquer coisa, pode me chamar por aqui.`;

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

